class Solution:
    def reverseDegree(self, s):
        reversed_alphabet = 'zyxwvutsrqponmlkjihgfedcba'
        total = 0
        for i in range(len(s)):
            value = reversed_alphabet.index(s[i]) + 1
            total += value * (i + 1)
        return total

